# ============ КРЫЛО: шаблон ============
def wing_page(slug,img,sci_img,cap,ew,title,lead,intro,states,progs,bullets,cls,labels,quote,fact,extra='',stats=None,shi=0):
    ecls={'w1':'','w2':'t','w3':'m'}.get(cls,'')
    statsec=''
    if stats:
        statsec='<section><div class="wrap"><div class="sec-h"><span class="eyebrow %s">Коротко в цифрах</span><h2>Что говорят исследования</h2></div>%s</div></section>' % (ecls, statband(stats, hi=shi, hic=ecls))
    st=''.join('<div class="wing %s"><div class="ic">%s</div><h3>%s</h3><p>%s</p></div>'%(cls,ic,h,p) for ic,h,p in states)
    bl=''.join(bullet(t,ic) for t,ic in bullets)
    twocol=''.join('<p>%s</p>'%p for p in intro[1:])
    fb='<div class="factbox %s"><div class="th">%s</div><p>%s</p><div class="src">%s</div></div>' % (ecls, fact[0], fact[1], fact[2])
    mq='<div class="miniquote %s"><q>%s</q><cite>%s</cite></div>' % (ecls, quote[0], quote[1])
    body='''
%s
<section><div class="wrap"><div class="introg">
<div><p class="lead">%s</p><div class="twocol">%s</div></div>
<div class="aside">%s%s</div>
</div></div></section>
<section class="soft"><div class="wrap"><div class="sec-h"><span class="eyebrow %s">Что внутри крыла</span><h2>С чем работаем</h2></div>
<div class="wings">%s</div></div></section>
<section><div class="wrap"><div class="sec-h"><span class="eyebrow %s">Программы крыла</span><h2>С чего начать</h2><p>Короткая запись, длинный маршрут с кабинетом или личная работа. Выбирай по силам.</p></div>
<div class="pgrid">%s</div></div></section>
<section class="soft"><div class="wrap"><div class="why"><div class="why-media"><img src="%s" alt=""><span class="cap"><span class="d"></span> %s</span></div>
<div><span class="eyebrow %s">Проверено наукой</span><h2 class="disp" style="font-size:clamp(21px,2.3vw,30px);margin:14px 0 8px;text-wrap:balance;max-width:20ch">Почему это работает</h2>
<ul class="thm-list %s">%s</ul></div></div></div></section>
%s%s%s
''' % (phero(img,ew,title,lead,title,labels), intro[0], twocol, mq, fb,
       ecls, st, ecls, progs, sci_img, cap, ecls, ecls, bl, statsec, extra,
       cta_band('Найди свою программу в этом крыле','Один вход по почте, весь маршрут на платформе, с прогрессом и практиками.','Смотреть все программы',U+'shop/'))
    page(slug,title+' — Архитектура сознания',body,lead,active=slug)

